const aiRaw = $('1. IA: guion del reel').first().json;
const trigger = $('Trigger').first().json;
const recordId = trigger.contentId || trigger.id || '';
const referenceImageUrl = $input.first().json.referenceImageUrl || '';

try {
  const content = aiRaw.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  const clips = parsed.clips || [];

  return clips.map(clip => ({
    json: {
      recordId,
      tenantId: trigger.tenantId || null,
      referenceImageUrl,
      clip_number: clip.clip_number,
      texto_en_pantalla: clip.texto_en_pantalla || '',
      narracion: clip.narracion || '',
      video_prompt: clip.video_prompt || ''
    }
  }));
} catch (e) {
  return [{ json: { recordId, tenantId: $('Trigger').first().json.tenantId, referenceImageUrl, error: 'Failed to parse: ' + e.message } }];
}

const raw = $input.first().json;
const scene = Array.isArray(raw) ? raw[0] : raw;
const clipData = $('3. Loop por clip').first().json;
return [{ json: { ...clipData, sceneId: scene.id } }];

const input = $input.first().json;
const sceneData = $('Extraer ID escena').first().json;
const escenaId = sceneData.sceneId;
const clipData = sceneData;

const isWaitCallback = !!(input.body && typeof input.body === 'object' && (input.body.code !== undefined || input.body.data !== undefined));
const callback = isWaitCallback ? input.body : input;

const apiCode = callback.code;
const apiMsg = callback.msg || '';
const failMsg = callback.data?.failMsg || '';

let videoRetryCount = 0;
try {
  const prev = $('7. Procesar video URL').first().json;
  if (prev.retryable && prev.escenaId === escenaId) {
    videoRetryCount = prev.videoRetryCount || 0;
  }
} catch (e) {}

const retryableCodes = [500, 501, 502, 503];
const retryableMessages = ['internal error', 'try again', 'server busy', 'temporarily unavailable'];
const isRetryableError = retryableCodes.includes(apiCode) || retryableMessages.some(m => (apiMsg + ' ' + failMsg).toLowerCase().includes(m));

if (apiCode !== undefined && apiCode !== 200 && isRetryableError && videoRetryCount < 3) {
  return [{ json: { escenaId, videoUrl: '', estado: 'Reintentando', retryable: true, videoRetryCount: videoRetryCount + 1, errorMsg: 'Retry ' + (videoRetryCount + 1) + '/3: code=' + apiCode + ' ' + apiMsg, narracion: clipData.narracion || '', fatalError: false, recordId: clipData.recordId, tenantId: clipData.tenantId } }];
}

if (apiCode !== undefined && apiCode !== 200) {
  return [{ json: { escenaId, videoUrl: '', estado: 'Error', retryable: false, videoRetryCount, errorMsg: 'Kie.ai Veo code=' + apiCode + ': ' + apiMsg, narracion: clipData.narracion || '', fatalError: true, recordId: clipData.recordId, tenantId: clipData.tenantId } }];
}

let videoUrl = '';
let estado = 'Generando audio';
let errorMsg = '';
try {
  const info = callback.data?.info;
  if (info && info.resultUrls && info.resultUrls[0]) { videoUrl = info.resultUrls[0]; }
  else if (info && info.result_urls && info.result_urls[0]) { videoUrl = info.result_urls[0]; }
  else if (callback.data?.resultJson) { const rj = JSON.parse(callback.data.resultJson); videoUrl = rj.resultUrls?.[0] || ''; }
} catch (e) { estado = 'Error'; errorMsg = 'Failed to parse callback: ' + e.message; }

if (!videoUrl && estado !== 'Error') { estado = 'Error'; errorMsg = isWaitCallback ? 'Callback de Kie.ai Veo sin video URL' : 'Timeout esperando callback de Kie.ai Veo (>20min).'; }

return [{ json: { escenaId, videoUrl, estado, errorMsg, narracion: clipData.narracion || '', fatalError: estado === 'Error', recordId: clipData.recordId, tenantId: clipData.tenantId } }];

const mergeResult = $input.first().json;
const escenaId = $('10c. Extraer URL audio').first().json.escenaId;
const timestamps = $('10c. Extraer URL audio').first().json.timestamps || null;

let estado = 'Listo';
const attachments = [];
let mergedUrl = '';

if (mergeResult.success && mergeResult.url) {
  mergedUrl = mergeResult.url;
  attachments.push({ url: mergedUrl });
} else {
  estado = 'Error';
  const videoUrl = $('10c. Extraer URL audio').first().json.videoUrl;
  if (videoUrl) attachments.push({ url: videoUrl });
}

return [{ json: { escenaId, estado, attachments, mergedUrl, timestamps } }];

const trigger = $('Trigger').first().json;
const recordId = trigger.contentId || trigger.id || '';
const tenantId = trigger.tenantId || null;

const items = $input.all();
const mergedUrls = [];

for (const item of items) {
  const mediaFinal = item.json.fields?.['media_final'] || item.json['media_final'] || null;
  if (mediaFinal) mergedUrls.push(mediaFinal);
}

const clips = $('2. Parsear clips').all();
const fullTranscript = clips
  .map(item => item.json.narracion || '')
  .filter(Boolean)
  .join(' ');

return [{ json: { recordId, tenantId, mergedUrls, fullTranscript, totalClips: items.length, okClips: mergedUrls.length } }];

