const concatResult = $input.first().json;
const juntarData = $('17. Juntar clips mergeados').first().json;
const recordId = juntarData.recordId;
const tenantId = juntarData.tenantId;
const fullTranscript = juntarData.fullTranscript || '';

const reelAttachments = [];
let reelUrl = '';
let estado = 'ready';

if (concatResult.success && concatResult.url) {
  reelUrl = concatResult.url;
  reelAttachments.push({ url: reelUrl });
} else {
  estado = 'error';
}

return [{ json: { recordId, tenantId, reelAttachments, reelUrl, fullTranscript, estado } }];

const trigger = $('Trigger').first().json;
const recordId = trigger.contentId || trigger.id || '';
const tenantId = trigger.tenantId || null;
const errorMsg = $('7. Procesar video URL').first().json.errorMsg || 'Error desconocido en generacion de video';
return [{ json: { recordId, tenantId, errorMsg } }];

const callback = $input.first().json;
const body = callback.body || callback;

const event = (body.event || '').toLowerCase();
const renderUrl = body.renderUrl || body.downloadUrl || '';
const errorMsg = body.error || body.errorMessage || body.message || '';

let estado = 'ready';
let attachments = [];
let error = '';

if (event === 'completed' && renderUrl) {
  attachments = [{ url: renderUrl }];
} else {
  estado = 'error';
  error = errorMsg || `ZapCap fallo (event=${event || 'desconocido'})`;
}

let zapcapRetryCount = 0;
try {
  const prev = $('24. Procesar ZapCap callback').first().json;
  if (prev.retryable) { zapcapRetryCount = prev.zapcapRetryCount || 0; }
} catch (e) {}

const retryableMessages = ['internal error', 'server error', 'try again', 'server busy', 'temporarily unavailable', 'timeout', '500', '502', '503'];
const isRetryableError = estado === 'error' && zapcapRetryCount < 3 && retryableMessages.some(m => error.toLowerCase().includes(m));

if (isRetryableError) {
  return [{ json: { estado: 'Reintentando', attachments: [], error: 'Retry ' + (zapcapRetryCount + 1) + '/3: ' + error, renderUrl: '', retryable: true, zapcapRetryCount: zapcapRetryCount + 1 } }];
}

return [{ json: { estado, attachments, error, renderUrl, retryable: false } }];

const brand = $('Trigger').first().json.brand || {};
const style = $('Trigger').first().json.style_prompts || {};
const trigger = $('Trigger').first().json;

let systemPrompt = style.prompt_sistema || '';
systemPrompt = systemPrompt
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{tono}/g, brand.tono || '')
  .replace(/{audiencia}/g, brand.audiencia || '')
  .replace(/{colores}/g, brand.colores || '')
  .replace(/{estilo_visual}/g, brand.estilo_visual || '')
  .replace(/{reglas_lenguaje}/g, brand.reglas_lenguaje || '');

if (!systemPrompt) {
  systemPrompt = `Eres un director de contenido para reels de Instagram de ${brand.nombre || 'la marca'}. Colores: ${brand.colores}. IDIOMA: textos en ESPANOL, video_prompt en ingles. SIEMPRE responde en JSON valido.`;
}

let userPrompt = style.prompt_usuario || '';
userPrompt = userPrompt
  .replace(/{mi_hook}/g, trigger.mi_hook || '')
  .replace(/{mi_caption}/g, trigger.mi_caption || '')
  .replace(/{analisis}/g, trigger.analisis || '')
  .replace(/{hook_original}/g, trigger.hook_original || '')
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{colores}/g, brand.colores || '');

if (!userPrompt) {
  userPrompt = `Genera un guion de reel con 3-5 clips de 8 segundos.\nHOOK: ${trigger.mi_hook || ''}\nCAPTION: ${trigger.mi_caption || ''}\nCONTEXTO: ${trigger.analisis || ''}\n\nJSON con clips[]: clip_number, texto_en_pantalla, narracion, video_prompt.`;
}

return [{ json: { ...trigger, systemPrompt, userPrompt } }];

// Build Veo body
const endpoint = 'https://api.kie.ai/api/v1/jobs/createTask';
const prompt = $('3. Loop por clip').first().json.video_prompt || '';
const referenceImageUrl = $('3. Loop por clip').first().json.referenceImageUrl || '';

const bodyObj = {
  type: 'text2video',
  model: 'veo-3.1',
  prompt: prompt,
  aspect_ratio: '9:16',
  duration: 8,
  callback_url: '{callback_url}'
};

if (referenceImageUrl) { bodyObj.reference_image = referenceImageUrl; bodyObj.type = 'img2video'; }

return [{ json: { endpoint, bodyWithCallback: JSON.stringify(bodyObj) } }];

// Build ElevenLabs TTS body via Kie.ai
const narracion = $('7. Procesar video URL').first().json.narracion || '';
const videoUrl = $('7. Procesar video URL').first().json.videoUrl || '';
const escenaId = $('7. Procesar video URL').first().json.escenaId || '';
const recordId = $('7. Procesar video URL').first().json.recordId || '';
const tenantId = $('7. Procesar video URL').first().json.tenantId || null;

const endpoint = 'https://api.kie.ai/api/v1/jobs/createTask';
const bodyObj = {
  type: 'tts',
  model: 'eleven_multilingual_v2',
  text: narracion,
  voice_id: 'Roger',
  callback_url: '{callback_url}'
};

return [{ json: { endpoint, bodyWithCallback: JSON.stringify(bodyObj), videoUrl, escenaId, recordId, tenantId } }];

const input = $input.first().json;
const bodyData = $('10. Build TTS body').first().json;

const isWaitCallback = !!(input.body && typeof input.body === 'object');
const callback = isWaitCallback ? input.body : input;

let audioUrl = '';
try {
  const resultJson = JSON.parse(callback.data?.resultJson || '{}');
  audioUrl = resultJson.resultUrls?.[0] || resultJson.audioUrl || '';
} catch (e) {}

return [{ json: { escenaId: bodyData.escenaId, audioUrl, estado: audioUrl ? 'Merging' : 'Error', videoUrl: bodyData.videoUrl, recordId: bodyData.recordId, tenantId: bodyData.tenantId } }];

const brand = $('Trigger').first().json.brand || {};
const videoId = $('21. ZapCap upload').first().json.id;

const body = {
  templateId: 'e659ee0c-53bb-497e-869c-90f8ec0a921f',
  autoApprove: true,
  language: 'es',
  renderOptions: {
    subsOptions: { emoji: false, animation: true, emphasizeKeywords: true, punctuation: true, displayWords: 2 },
    styleOptions: { top: 78, fontUppercase: true, fontSize: 32, fontWeight: 900 },
    highlightOptions: {}
  },
  notification: { type: 'webhook', notificationsFor: ['render'], recipient: '{callback_url}' }
};

return [{ json: { videoId, zapcapBody: JSON.stringify(body) } }];
